// Inject a controlled, realistic dataset for the Mike's HVAC demo.
// Same shape as the Normalize Live Data output so downstream nodes don't care which path ran.

const config = $('Config').first().json;
const now = new Date();
const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const dateLabel = `${dayNames[now.getDay()]}, ${months[now.getMonth()]} ${now.getDate()}`;

return [{
  json: {
    config,
    date_label: dateLabel,
    overdue_tasks: [
      { content: "Call Sarah Martinez re: AC unit estimate", priority: "P1", days_overdue: 2, deadline_today: true },
      { content: "Send revised quote to Valley Fitness", priority: "P2", days_overdue: 1 },
      { content: "Follow up — Johnson kitchen remodel (proposal sent 9 days ago)", priority: "P2", days_overdue: 1 }
    ],
    today_tasks: [
      { content: "Prep notes for 11:30 Valley Fitness call", priority: "P1" },
      { content: "Order replacement compressor for 742 Elm install", priority: "P2" },
      { content: "Review insurance renewal docs", priority: "P3" }
    ],
    calendar_events: [
      { time: "9:00 AM", summary: "Site visit — 742 Elm St (AC install estimate)" },
      { time: "11:30 AM", summary: "Call with Valley Fitness (proposal review)" },
      { time: "2:00 PM", summary: "Johnson kitchen follow-up" },
      { time: "4:00 PM", summary: "New client intro — Camarillo Dental" }
    ],
    priority_emails: [
      { from: "sarah.martinez@gmail.com", subject: "Re: AC quote — when can you come out?", received: "11:47 PM (last night)" },
      { from: "jen@valleyfitness.com", subject: "Quick question before our 11:30", received: "7:14 AM" },
      { from: "office@johnsonremodel.com", subject: "Decision update", received: "6:02 AM" }
    ],
    pipeline: {
      deals_closing_this_week: 3,
      total_value_closing: 18400,
      stale_deals: [
        { name: "Johnson kitchen remodel", value: 8200, days_stale: 9, stage: "Proposal Sent" }
      ],
      new_lead: { name: "Sarah Martinez", source: "website form", est_value: 4200, received: "11:47 PM last night" }
    }
  }
}];

// Normalize the three live API outputs into the same shape as Seed Demo Data.
// Reach back to each fetch node by name so we don't depend on merge order.

const config = $('Config').first().json;
const now = new Date();
const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const dateLabel = `${dayNames[now.getDay()]}, ${months[now.getMonth()]} ${now.getDate()}`;

// --- Todoist ---
let overdue = [];
let today = [];
try {
  const todoistItems = $('Todoist: Today + Overdue').all().map(i => i.json);
  const priorityMap = { 4: 'P1', 3: 'P2', 2: 'P3', 1: 'P4' };
  for (const t of todoistItems) {
    const dueDate = t.due ? new Date(t.due.date) : null;
    const isOverdue = dueDate && dueDate < new Date(now.toDateString());
    const entry = {
      content: t.content,
      priority: priorityMap[t.priority] || 'P4',
      due_string: t.due ? t.due.string : ''
    };
    if (isOverdue) {
      entry.days_overdue = Math.floor((now - dueDate) / 86400000);
      overdue.push(entry);
    } else {
      today.push(entry);
    }
  }
} catch (e) { /* todoist node returned nothing */ }

// --- Calendar ---
let calendarEvents = [];
try {
  const events = $("Calendar: Today's Events").all().map(i => i.json);
  calendarEvents = events.map(e => {
    const startISO = e.start && (e.start.dateTime || e.start.date);
    const startD = startISO ? new Date(startISO) : null;
    const time = startD ? startD.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }) : 'All day';
    return { time, summary: e.summary || '(no title)' };
  });
} catch (e) { /* calendar credential missing or no events */ }

// --- Gmail ---
let priorityEmails = [];
try {
  const msgs = $('Gmail: Priority Unread').all().map(i => i.json);
  priorityEmails = msgs.slice(0, 5).map(m => {
    const headers = (m.payload && m.payload.headers) || [];
    const fromHeader = headers.find(h => h.name === 'From');
    const subjHeader = headers.find(h => h.name === 'Subject');
    return {
      from: fromHeader ? fromHeader.value : (m.from || ''),
      subject: subjHeader ? subjHeader.value : (m.subject || m.snippet || ''),
      received: m.internalDate ? new Date(parseInt(m.internalDate)).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }) : ''
    };
  });
} catch (e) { /* no priority emails */ }

return [{
  json: {
    config,
    date_label: dateLabel,
    overdue_tasks: overdue,
    today_tasks: today,
    calendar_events: calendarEvents,
    priority_emails: priorityEmails,
    pipeline: null
  }
}];

// Parse Claude response, then build both Gmail HTML and Slack markdown outputs.
const input = $input.first().json;
const config = $('Config').first().json;
const dateLabel = ($('Merge Paths').first().json.date_label) || '';

const briefingMd = (input.content && input.content[0] && input.content[0].text) || '(no briefing generated)';

// Minimal markdown → HTML for the email. Translates **bold**, line breaks, and bulleted/numbered lists.
function mdToHtml(md) {
  const lines = md.split(/\r?\n/);
  let html = '';
  let inList = false;
  let listType = null;
  for (const raw of lines) {
    let line = raw.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    const numMatch = line.match(/^\s*(\d+)\.\s+(.+)$/);
    const bulletMatch = line.match(/^\s*[-•]\s+(.+)$/);
    if (numMatch) {
      if (!inList || listType !== 'ol') { if (inList) html += `</${listType}>`; html += '<ol style="padding-left:20px;margin:8px 0;">'; inList = true; listType = 'ol'; }
      html += `<li style="margin:4px 0;">${numMatch[2]}</li>`;
    } else if (bulletMatch) {
      if (!inList || listType !== 'ul') { if (inList) html += `</${listType}>`; html += '<ul style="padding-left:20px;margin:8px 0;">'; inList = true; listType = 'ul'; }
      html += `<li style="margin:4px 0;">${bulletMatch[1]}</li>`;
    } else {
      if (inList) { html += `</${listType}>`; inList = false; listType = null; }
      if (line.trim() === '') html += '<div style="height:8px;"></div>';
      else html += `<p style="margin:6px 0;line-height:1.5;">${line}</p>`;
    }
  }
  if (inList) html += `</${listType}>`;
  return html;
}

const bodyHtml = mdToHtml(briefingMd);
const fullHtml = `<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f4f4f7;"><div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:640px;margin:24px auto;color:#1a1a1a;background:white;border-radius:12px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,0.06);"><div style="background:#0f172a;color:white;padding:20px 24px;"><div style="font-size:12px;letter-spacing:2px;text-transform:uppercase;opacity:0.7;">${config.persona.business_name}</div><h1 style="margin:6px 0 0;font-size:22px;font-weight:600;">Morning Briefing — ${dateLabel}</h1></div><div style="padding:24px;">${bodyHtml}</div><div style="background:#f8fafc;color:#64748b;padding:14px 24px;font-size:11px;text-align:center;border-top:1px solid #e2e8f0;">Generated by AgentTree · ${dateLabel}</div></div></body></html>`;

// Slack uses *bold* not **bold**
const slackText = briefingMd.replace(/\*\*(.+?)\*\*/g, '*$1*');
const subject = `Daily Briefing — ${dateLabel}`;

return [{
  json: { config, subject, body_markdown: briefingMd, body_html: fullHtml, slack_text: slackText }
}];
